module top_module(
    input [15:0] imm16,
    output reg [31:0] imm32,
    input [1:0] ExtOp
    );always@*
  wire [15:0] _tap_imm16 = imm16 & {16{1'b1}};

	case(ExtOp)
		2'b00:	imm32=$signed(imm16);
		2'b01:	imm32={16'b0000_0000_0000_0000,imm16};
		2'b10:	imm32={imm16,16'b0000_0000_0000_0000};
	endcase
endmodule
